// Obtener última semana automáticamente
const semanas = items
  .map(i => Number(i.json["Semana g"] || i.json["Semana I"] || 0))
  .filter(n => n > 0);

const ultimaSemana = Math.max(...semanas);

// Obtener mes actual basado en fechas existentes
function getMes(fecha) {
  if (!fecha) return null;
  const [dia, mes, anio] = fecha.split("/");
  return mes + "/" + anio;
}

// Detectar mes más reciente
const meses = items
  .map(i => getMes(i.json["Fecha g"] || i.json["Fecha I"]))
  .filter(m => m);

const mesActual = meses.sort().pop();

// Estructuras
let resumen = {
  ultimaSemana: {
    gastos: {},
    ingresos: {}
  },
  mensual: {
    gastos: { Efectivo: 0, Tarjeta: 0 },
    ingresos: { Efectivo: 0, Tarjeta: 0 }
  }
};

// Recorrer datos
for (const item of items) {
  const data = item.json;

  // ----------- GASTOS (g) -----------
  const semanaG = Number(data["Semana g"]);
  const tipoG = data["Tipo g"];
  const categoriaG = data["Categoría g"];
  const importeG = Number(data["Importe g"] || 0);
  const mesG = getMes(data["Fecha g"]);

  if (importeG > 0) {

    // Última semana
    if (semanaG === ultimaSemana) {
      if (!resumen.ultimaSemana.gastos[categoriaG]) {
        resumen.ultimaSemana.gastos[categoriaG] = { Efectivo: 0, Tarjeta: 0 };
      }
      resumen.ultimaSemana.gastos[categoriaG][tipoG] += importeG;
    }

    // Mensual
    if (mesG === mesActual) {
      resumen.mensual.gastos[tipoG] += importeG;
    }
  }

  // ----------- INGRESOS (i) -----------
  const semanaI = Number(data["Semana I"]);
  const tipoI = data["Tipo i"];
  const categoriaI = data["Categoría I"];
  const importeI = Number(data["Importe I"] || 0);
  const mesI = getMes(data["Fecha I"]);

  if (importeI > 0) {

    // Última semana
    if (semanaI === ultimaSemana) {
      if (!resumen.ultimaSemana.ingresos[categoriaI]) {
        resumen.ultimaSemana.ingresos[categoriaI] = { Efectivo: 0, Tarjeta: 0 };
      }
      resumen.ultimaSemana.ingresos[categoriaI][tipoI] += importeI;
    }

    // Mensual
    if (mesI === mesActual) {
      resumen.mensual.ingresos[tipoI] += importeI;
    }
  }
}

// ----------- BALANCE MENSUAL -----------
const balance = {
  Efectivo:
    resumen.mensual.ingresos.Efectivo -
    resumen.mensual.gastos.Efectivo,
  Tarjeta:
    resumen.mensual.ingresos.Tarjeta -
    resumen.mensual.gastos.Tarjeta
};

balance.Total = balance.Efectivo + balance.Tarjeta;

resumen.balanceMensual = balance;

return [{ json: resumen }];

